import{_ as s,o as a,c as t,ai as r}from"./chunks/framework.Bke2s2V8.js";const m=JSON.parse('{"title":"Le pluriel","description":"","frontmatter":{"next":{"text":"Module 2 - Construire une phrase","link":"../module-2-construire-une-phrase/"}},"headers":[],"relativePath":"module-1-fondations/le-pluriel.md","filePath":"module-1-fondations/le-pluriel.md","lastUpdated":1773298982000}'),n={name:"module-1-fondations/le-pluriel.md"};function l(d,e,i,o,p,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="le-pluriel" tabindex="-1">Le pluriel <a class="header-anchor" href="#le-pluriel" aria-label="Permalink to “Le pluriel”">​</a></h1><p><strong>Prérequis :</strong> <a href="./le-genre-des-noms.html">Le genre des noms</a></p><p><strong>Objectif :</strong> former le pluriel des noms courants et comprendre les 5 terminaisons possibles.</p><p>Le pluriel en allemand est plus complexe qu&#39;en français - il n&#39;y a pas une seule règle. Il existe 5 terminaisons différentes, et certains noms peuvent aussi prendre un umlaut (tréma) sur leur voyelle. La bonne nouvelle : au pluriel, tous les noms prennent l&#39;article <strong>die</strong>.</p><h2 id="les-5-terminaisons-du-pluriel" tabindex="-1">Les 5 terminaisons du pluriel <a class="header-anchor" href="#les-5-terminaisons-du-pluriel" aria-label="Permalink to “Les 5 terminaisons du pluriel”">​</a></h2><div class="mt-6 grid gap-4"><div class="p-4 rounded-xl border border-gray-200"><div class="flex items-center gap-3 mb-3"><span class="text-xl font-black text-green-600 w-16 text-center">-</span><div class="font-semibold text-gray-900">Pas de changement</div></div><div class="text-sm text-gray-600">Noms se terminant par <strong>-el, -en, -er</strong> restent identiques. Certains prennent un umlaut.</div><div class="mt-2 flex flex-wrap gap-2"><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">der Lehrer → die Lehrer</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">das Messer → die Messer</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">der Apfel → die Äpfel (avec umlaut)</span></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="flex items-center gap-3 mb-3"><span class="text-xl font-black text-green-600 w-16 text-center">-e</span><div class="font-semibold text-gray-900">Ajout d&#39;un -e</div></div><div class="text-sm text-gray-600">La terminaison la plus courante pour les noms masculins et neutres. Beaucoup prennent aussi un umlaut.</div><div class="mt-2 flex flex-wrap gap-2"><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">der Hund → die Hunde</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">das Jahr → die Jahre</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">der Hut → die Hüte (avec umlaut)</span></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="flex items-center gap-3 mb-3"><span class="text-xl font-black text-green-600 w-16 text-center">-er</span><div class="font-semibold text-gray-900">Ajout d&#39;un -er</div></div><div class="text-sm text-gray-600">Principalement les noms neutres monosyllabiques. Prend presque toujours un umlaut si possible.</div><div class="mt-2 flex flex-wrap gap-2"><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">das Kind → die Kinder</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">das Buch → die Bücher</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">der Mann → die Männer</span></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="flex items-center gap-3 mb-3"><span class="text-xl font-black text-green-600 w-16 text-center">-en / -n</span><div class="font-semibold text-gray-900">Ajout d&#39;un -en ou -n</div></div><div class="text-sm text-gray-600">La terminaison majoritaire des noms feminins. Jamais d&#39;umlaut avec cette terminaison.</div><div class="mt-2 flex flex-wrap gap-2"><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">die Frau → die Frauen</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">die Tür → die Türen</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">die Lampe → die Lampen</span></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="flex items-center gap-3 mb-3"><span class="text-xl font-black text-green-600 w-16 text-center">-s</span><div class="font-semibold text-gray-900">Ajout d&#39;un -s</div></div><div class="text-sm text-gray-600">Principalement les mots d&#39;origine étrangère et les abreviations. Jamais d&#39;umlaut.</div><div class="mt-2 flex flex-wrap gap-2"><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">das Auto → die Autos</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">das Hotel → die Hotels</span><span class="text-xs bg-gray-100 text-gray-700 px-2 py-1 rounded">das Café → die Cafés</span></div></div></div><h2 id="indices-selon-le-genre" tabindex="-1">Indices selon le genre <a class="header-anchor" href="#indices-selon-le-genre" aria-label="Permalink to “Indices selon le genre”">​</a></h2><p>Même sans connaître le pluriel exact, ces tendances aident :</p><table tabindex="0"><thead><tr><th>Genre</th><th>Terminaison la plus frequente</th><th>Exemple</th></tr></thead><tbody><tr><td>Masculin (der)</td><td>-e (avec ou sans umlaut)</td><td>der Tag → die Tage</td></tr><tr><td>Féminin (die)</td><td>-en / -n</td><td>die Zeitung → die Zeitungen</td></tr><tr><td>Neutre (das)</td><td>-e ou -er (souvent avec umlaut)</td><td>das Buch → die Bücher</td></tr></tbody></table><h2 id="cas-particuliers" tabindex="-1">Cas particuliers <a class="header-anchor" href="#cas-particuliers" aria-label="Permalink to “Cas particuliers”">​</a></h2><p><strong>Les diminutifs en -chen et -lein</strong> ne changent jamais au pluriel :</p><ul><li><em>das Mädchen</em> → <em>die Mädchen</em></li><li><em>das Häuschen</em> → <em>die Häuschen</em></li></ul><p><strong>Certains noms n&#39;ont pas de pluriel</strong> (comme les matières abstraites) :</p><ul><li><em>die Musik, das Wasser, das Gold</em></li></ul><div class="warning custom-block"><p class="custom-block-title">Pas de pluriel pour les matieres et substances</p><p>Les noms de matieres, substances et concepts abstraits n&#39;ont généralement pas de pluriel en allemand, comme en français. <em>Zwei Wasser</em> pour commander de l&#39;eau au restaurant est cependant accepte oralement.</p></div><h2 id="conseil" tabindex="-1">Conseil <a class="header-anchor" href="#conseil" aria-label="Permalink to “Conseil”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Apprendre trois informations par nom</p><p>Pour chaque nouveau nom : l&#39;article, le nom, et le pluriel. Par exemple : <strong>der Hund - die Hunde</strong> ou <strong>das Buch - die Bücher</strong>. Un peu plus de travail au début, beaucoup moins d&#39;erreurs ensuite.</p></div>',17)])])}const x=s(n,[["render",l]]);export{m as __pageData,x as default};
